import random

class RandomSampler:
    def __init__(self, rate: float):
        if not 0.0 < rate <= 1.0:
            raise ValueError(f"rate must be in (0, 1], got {rate}")
        self.rate = rate

    def should_sample(self, _request: dict) -> bool:
        return random.random() < self.rate

from dataclasses import dataclass, field
from enum import Enum
import random

class RequestStratum(str, Enum):
    STRUCTURED_OUTPUT = "structured_output"   # JSON mode, function calls
    LONG_CONTEXT      = "long_context"         # >16k tokens input
    TOOL_USE          = "tool_use"             # tool_use blocks present
    STANDARD          = "standard"             # everything else

@dataclass
class StratumConfig:
    rate: float          # sample rate 0–1
    max_per_minute: int  # hard cap to prevent burst

@dataclass
class StratifiedSampler:
    strata_config: dict[RequestStratum, StratumConfig]
    _counts: dict[RequestStratum, int] = field(default_factory=dict)

    def classify(self, request: dict) -> RequestStratum:
        if any(b.get("type") == "tool_use" for b in request.get("content", []) if isinstance(b, dict)):
            return RequestStratum.TOOL_USE
        total_chars = sum(
            len(m.get("content", "")) for m in request.get("messages", [])
            if isinstance(m.get("content"), str)
        )
        if total_chars > 60_000:   # ~16k tokens at ~4 chars/token
            return RequestStratum.LONG_CONTEXT
        if request.get("response_format", {}).get("type") == "json_object":
            return RequestStratum.STRUCTURED_OUTPUT
        return RequestStratum.STANDARD

    def should_sample(self, request: dict) -> tuple[bool, RequestStratum]:
        stratum = self.classify(request)
        cfg = self.strata_config.get(stratum, StratumConfig(rate=0.01, max_per_minute=30))
        minute_key = stratum
        count = self._counts.get(minute_key, 0)
        if count >= cfg.max_per_minute:
            return False, stratum
        if random.random() >= cfg.rate:
            return False, stratum
        self._counts[minute_key] = count + 1
        return True, stratum

PRODUCTION_STRATA = {
    RequestStratum.STRUCTURED_OUTPUT: StratumConfig(rate=0.05, max_per_minute=200),
    RequestStratum.LONG_CONTEXT:      StratumConfig(rate=0.10, max_per_minute=100),
    RequestStratum.TOOL_USE:          StratumConfig(rate=0.05, max_per_minute=300),
    RequestStratum.STANDARD:          StratumConfig(rate=0.02, max_per_minute=500),
}

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
import asyncio, json

class EvalStatus(str, Enum):
    PENDING   = "pending"
    RUNNING   = "running"
    COMPLETE  = "complete"
    FAILED    = "failed"

@dataclass
class EvalJob:
    job_id: str
    request_id: str
    request_payload: dict
    response_payload: dict
    stratum: str
    triggers: list[str]
    queued_at: datetime
    status: EvalStatus = EvalStatus.PENDING
    result: dict | None = None

class EvalQueue:
    def __init__(self, maxsize: int = 10_000):
        self._queue: asyncio.Queue[EvalJob] = asyncio.Queue(maxsize=maxsize)
        self._dropped = 0

    async def enqueue(self, job: EvalJob) -> bool:
        try:
            self._queue.put_nowait(job)
            return True
        except asyncio.QueueFull:
            self._dropped += 1
            return False

    async def dequeue(self) -> EvalJob:
        return await self._queue.get()

    @property
    def depth(self) -> int:
        return self._queue.qsize()

    @property
    def dropped(self) -> int:
        return self._dropped

from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime, timedelta
import statistics

@dataclass
class MetricsBucket:
    window_start: datetime
    window_end: datetime
    stratum: str
    count: int = 0
    score_sum: float = 0.0
    scores: list[float] = field(default_factory=list)
    flag_counts: dict[str, int] = field(default_factory=lambda: defaultdict(int))

    def add_verdict(self, verdict: EvalVerdict) -> None:
        self.count += 1
        self.score_sum += verdict.overall_score
        self.scores.append(verdict.overall_score)
        for flag in verdict.flags:
            self.flag_counts[flag] += 1

    @property
    def mean_score(self) -> float:
        return self.score_sum / self.count if self.count else 0.0

    @property
    def p10_score(self) -> float:
        if not self.scores:
            return 0.0
        return sorted(self.scores)[max(0, int(len(self.scores) * 0.1) - 1)]

    def flag_rate(self, flag: str) -> float:
        return self.flag_counts.get(flag, 0) / self.count if self.count else 0.0

    def bucket_summary(self) -> dict:
        return {
            "window": f"{self.window_start.isoformat()} – {self.window_end.isoformat()}",
            "stratum": self.stratum,
            "count": self.count,
            "mean_score": round(self.mean_score, 3),
            "p10_score": round(self.p10_score, 3),
            "flag_rates": {k: round(v, 4) for k, v in self.flag_counts.items()},
        }

from dataclasses import dataclass
from enum import Enum

class AlertSeverity(str, Enum):
    WARNING  = "warning"   # degradation worth investigating
    CRITICAL = "critical"  # degradation requiring immediate response

@dataclass
class AlertRule:
    name: str
    stratum: str
    metric: str            # "mean_score" | "p10_score" | flag name
    threshold_drop: float  # absolute drop from baseline triggering alert
    severity: AlertSeverity

@dataclass
class Alert:
    rule: AlertRule
    baseline_value: float
    current_value: float
    window_start: str

    @property
    def drop(self) -> float:
        return self.baseline_value - self.current_value

    def alert_message(self) -> str:
        return (
            f"[{self.rule.severity.upper()}] {self.rule.name}: "
            f"{self.rule.metric} for {self.rule.stratum} dropped "
            f"{self.drop:.3f} (baseline {self.baseline_value:.3f} → "
            f"current {self.current_value:.3f}) since {self.window_start}"
        )

ALERT_RULES: list[AlertRule] = [
    AlertRule("mean_score_drop_warning",  "standard",  "mean_score",  0.05, AlertSeverity.WARNING),
    AlertRule("mean_score_drop_critical", "standard",  "mean_score",  0.10, AlertSeverity.CRITICAL),
    AlertRule("p10_score_drop",           "standard",  "p10_score",   0.10, AlertSeverity.WARNING),
    AlertRule("safety_flag_spike",        "standard",  "safety_concern", 0.02, AlertSeverity.CRITICAL),
    AlertRule("tool_use_accuracy_drop",   "tool_use",  "mean_score",  0.07, AlertSeverity.WARNING),
    AlertRule("structured_format_drop",   "structured_output", "format", 0.08, AlertSeverity.WARNING),
]

def evaluate_alerts(
    current: MetricsBucket,
    baseline: MetricsBucket,
    rules: list[AlertRule],
) -> list[Alert]:
    alerts = []
    for rule in rules:
        if rule.stratum != current.stratum:
            continue
        if rule.metric in ("mean_score", "p10_score"):
            baseline_val = getattr(baseline, rule.metric)
            current_val  = getattr(current, rule.metric)
        else:
            baseline_val = baseline.flag_rate(rule.metric)
            current_val  = current.flag_rate(rule.metric)
        drop = baseline_val - current_val
        if drop >= rule.threshold_drop:
            alerts.append(Alert(rule, baseline_val, current_val, current.window_start.isoformat()))
    return alerts
